from delivery.client_pool import ClientPool
from delivery.config import load_endpoint
from delivery.router import DeliveryRouter


def receipt_config(receipt):
    return receipt.endpoint, receipt.credential


def test_reload_from_canary_to_blank_override_uses_new_base_snapshot():
    pool = ClientPool()
    canary = load_endpoint(
        {
            "service": "events",
            "endpoint": "https://old-base.invalid",
            "token": "old-base-token",
            "revision": 20,
        },
        {
            "DELIVERY_ENDPOINT": "https://canary-20.invalid",
            "DELIVERY_TOKEN": "canary-20-token",
        },
    )
    router = DeliveryRouter(canary, pool)
    assert receipt_config(router.deliver("inventory", 1)) == (
        "https://canary-20.invalid",
        "canary-20-token",
    )

    stable = load_endpoint(
        {
            "service": "events",
            "endpoint": "https://stable-21.invalid",
            "token": "stable-21-token",
            "revision": 21,
        },
        {
            "DELIVERY_ENDPOINT": "",
            "DELIVERY_TOKEN": "",
            "DELIVERY_REVISION": "21",
        },
    )
    router.reload(stable)
    recurring = router.deliver("inventory", 2)
    new_topic = router.deliver("catalog", 3)
    assert receipt_config(recurring) == (
        "https://stable-21.invalid",
        "stable-21-token",
    )
    assert receipt_config(new_topic) == (
        "https://stable-21.invalid",
        "stable-21-token",
    )


def test_shared_pool_keeps_same_service_snapshots_distinct():
    pool = ClientPool()
    blue = load_endpoint(
        {
            "service": "events",
            "endpoint": "https://blue.invalid",
            "token": "blue-token",
            "revision": 30,
        },
        {},
    )
    green = load_endpoint(
        {
            "service": "events",
            "endpoint": "https://green.invalid",
            "token": "green-token",
            "revision": 31,
        },
        {},
    )
    blue_receipt = DeliveryRouter(blue, pool).deliver("blue-topic", "b")
    green_receipt = DeliveryRouter(green, pool).deliver("green-topic", "g")
    assert receipt_config(blue_receipt) == (
        "https://blue.invalid",
        "blue-token",
    )
    assert receipt_config(green_receipt) == (
        "https://green.invalid",
        "green-token",
    )
